using System.IdentityModel.Tokens.Jwt; using System.Security.Claims; using System.Text; using FlightAPI.Data; using FlightAPI.DTOs; using FlightAPI.Models; using Microsoft.AspNetCore.Mvc; using Microsoft.EntityFrameworkCore; using Microsoft.IdentityModel.Tokens;
namespace FlightAPI.Controllers;
[ApiController, Route("api/auth")]
public class AuthController : ControllerBase { private readonly AppDbContext _db; private readonly IConfiguration _cfg; public AuthController(AppDbContext db,IConfiguration cfg){_db=db;_cfg=cfg;}
[HttpPost("register")] public async Task<IActionResult> Register(RegisterDto d){ if(await _db.Users.AnyAsync(u=>u.Email==d.Email)) return BadRequest(new{message="Email already exists"}); var u=new User{FullName=d.FullName,Email=d.Email,PasswordHash=BCrypt.Net.BCrypt.HashPassword(d.Password),Role="User"}; _db.Users.Add(u); await _db.SaveChangesAsync(); return Ok(new{message="Registered successfully"}); }
[HttpPost("login")] public async Task<IActionResult> Login(LoginDto d){ var u=await _db.Users.FirstOrDefaultAsync(x=>x.Email==d.Email); if(u==null||!BCrypt.Net.BCrypt.Verify(d.Password,u.PasswordHash)) return Unauthorized(new{message="Invalid credentials"}); var claims=new[]{new Claim(ClaimTypes.NameIdentifier,u.Id.ToString()),new Claim(ClaimTypes.Email,u.Email),new Claim(ClaimTypes.Role,u.Role),new Claim(ClaimTypes.Name,u.FullName)}; var key=new SymmetricSecurityKey(Encoding.UTF8.GetBytes(_cfg["Jwt:Key"]!)); var token=new JwtSecurityToken(_cfg["Jwt:Issuer"],_cfg["Jwt:Audience"],claims,expires:DateTime.UtcNow.AddHours(8),signingCredentials:new SigningCredentials(key,SecurityAlgorithms.HmacSha256)); return Ok(new{token=new JwtSecurityTokenHandler().WriteToken(token),user=new{u.Id,u.FullName,u.Email,u.Role}}); }
}
